class Solution:
    def capitalizeTitle(self, title: str) -> str:
        chars = list(title)
        n = len(chars)
        i = 0
        out = []
        while i < n:
            j = i
            word = []
            while j < n and chars[j] != ' ':
                word.append(chars[j])
                j += 1
            if len(word) <= 2:
                word = [c.lower() for c in word]
            else:
                word[0] = word[0].upper()
                for k in range(1, len(word)):
                    word[k] = word[k].lower()
            out.append(''.join(word))
            if j < n:
                out.append(' ')
            i = j + 1
        return ''.join(out)

