class Solution:
    def capitalizeTitle(self, title: str) -> str:
        words = title.split(' ')
        result = []
        for w in words:
            if len(w) <= 2:
                result.append(w.lower())
            else:
                result.append(w[0].upper() + w[1:].lower())
        return ' '.join(result)

